CREATE TABLE IF NOT EXISTS custom_requests (id INTEGER PRIMARY KEY AUTOINCREMENT,reference TEXT NOT NULL UNIQUE,guest_id INTEGER,guest_name TEXT NOT NULL,contact_method TEXT NOT NULL,contact_value TEXT NOT NULL,request_type TEXT NOT NULL,format_details TEXT NOT NULL DEFAULT '',personal_name TEXT NOT NULL DEFAULT '',brief TEXT NOT NULL,budget_band TEXT NOT NULL,deadline TEXT,quote_cents INTEGER NOT NULL DEFAULT 0,amount_paid_cents INTEGER NOT NULL DEFAULT 0,payment_status TEXT NOT NULL DEFAULT 'unpaid' CHECK(payment_status IN('unpaid','deposit','paid')),status TEXT NOT NULL DEFAULT 'new' CHECK(status IN('new','reviewing','quoted','accepted','creating','ready','delivered','declined')),delivery_url TEXT NOT NULL DEFAULT '',private_notes TEXT NOT NULL DEFAULT '',created_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP,updated_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP);
CREATE INDEX IF NOT EXISTS custom_requests_status_idx ON custom_requests(status,created_at DESC);
